// Convert Chinese text to Nüshu
function toNushu(text) {
  let result = '';
  for (const char of text) {
    if (NUSHU_MAP[char]) {
      result += NUSHU_MAP[char];
    } else {
      result += char; // Keep unmapped characters as-is
    }
  }
  return result;
}

// Check if a character has Nüshu mapping
function hasNushuMapping(char) {
  return !!NUSHU_MAP[char];
}
